# torch_ios: `safetensors` shim.
#
# Real safetensors is Rust + PyO3; we haven't cross-compiled for iOS arm64.
# Transformers unconditionally imports `from safetensors.torch import storage_ptr, storage_size`
# at module load time (pytorch_utils.py), so we need real working impls of those two.
#
# Everything else (load_file/save_file/safe_open) is guarded by runtime feature
# detection (is_safetensors_available) or lives on paths the smoke test / typical
# forward-pass usage doesn't exercise. Stubs raise NotImplementedError so you get
# a clear error if you accidentally hit the weight-loading path.

__version__ = "0.4.5"


class SafetensorError(Exception):
    pass


def safe_open(*args, **kwargs):
    raise NotImplementedError(
        "safetensors.safe_open: torch_ios shim does not support .safetensors file I/O. "
        "Construct models from config rather than loading weight files."
    )


__all__ = ["__version__", "SafetensorError", "safe_open"]
